type_mapping.example:
# Backend (backend/app/models/schemas.py):
class ChatRequest(BaseModel):
    session_id: str
    message: str = Field(..., min_length=1)
    context: dict[str, Any] = Field(default_factory=dict)

class ChatResponse(BaseModel):
    session_id: str
    content: str

# Frontend (src/types/api.ts):
export interface ChatRequest {
  session_id: string;
  message: string;
  context?: Record<string, unknown>;
}

export interface ChatResponse {
  session_id: string;
  content: string;
}

export interface ApiError {
  detail: string;  // FastAPI default error shape
}

api_client_pattern.template:
// src/lib/api.ts
const BASE_URL = import.meta.env.VITE_API_BASE_URL ?? '';

async function request<T>(
  path: string,
  options?: RequestInit
): Promise<T> {
  const response = await fetch(`${BASE_URL}${path}`, {
    headers: {
      'Content-Type': 'application/json',
      ...(import.meta.env.VITE_API_KEY
        ? { 'X-API-Key': import.meta.env.VITE_API_KEY }
        : {}),
    },
    ...options,
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({ detail: 'Unknown error' }));
    throw new ApiError(response.status, error.detail ?? 'Request failed');
  }

  return response.json() as Promise<T>;
}

export class ApiError extends Error {
  constructor(public status: number, message: string) {
    super(message);
    this.name = 'ApiError';
  }
}

// One function per endpoint — names derived from route purpose:
export async function sendChatMessage(body: ChatRequest): Promise<ChatResponse> {
  return request<ChatResponse>('/api/v1/chat', {
    method: 'POST',
    body: JSON.stringify(body),
  });
}

export async function getHealth(): Promise<HealthResponse> {
  return request<HealthResponse>('/api/v1/health');
}

vite_proxy_config.template:
// vite.config.ts
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  server: {
    port: 5173,
    proxy: {
      '/api': {
        target: 'http://localhost:8000',  // match backend port
        changeOrigin: true,
      },
    },
  },
});

custom_hooks_pattern.template:
// src/hooks/useChat.ts
import { useState, useCallback } from 'react';
import { sendChatMessage, ApiError } from '@/lib/api';
import type { ChatResponse } from '@/types/api';

export function useChat(sessionId: string) {
  const [messages, setMessages] = useState<ChatResponse[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const send = useCallback(async (message: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await sendChatMessage({ session_id: sessionId, message });
      setMessages(prev => [...prev, response]);
    } catch (err) {
      if (err instanceof ApiError) {
        setError(err.message);
      } else {
        setError('Unexpected error. Check the backend is running.');
      }
    } finally {
      setIsLoading(false);
    }
  }, [sessionId]);

  return { messages, isLoading, error, send };
}

session_management.pattern:
// src/lib/session.ts
export function getSessionId(): string {
  const existing = sessionStorage.getItem('session_id');
  if (existing) return existing;
  const id = `session-${crypto.randomUUID()}`;
  sessionStorage.setItem('session_id', id);
  return id;
}

streaming_pattern.sse_pattern:
// For Server-Sent Events streaming endpoint:
export async function* streamChat(body: ChatRequest): AsyncGenerator<string> {
  const response = await fetch('/api/v1/chat/stream', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });

  if (!response.body) throw new Error('No response body');
  const reader = response.body.getReader();
  const decoder = new TextDecoder();

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    const chunk = decoder.decode(value, { stream: true });
    // Parse SSE format: "data: {...}\n\n"
    for (const line of chunk.split('\n')) {
      if (line.startsWith('data: ') && line !== 'data: [DONE]') {
        try {
          const parsed = JSON.parse(line.slice(6));
          if (parsed.token) yield parsed.token as string;
        } catch { /* skip malformed lines */ }
      }
    }
  }
}
